import React, { useEffect, useState } from 'react';
import api from '../services/api';

export default function ReelsPage() {
  const [reels, setReels] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    api
      .get('/movie-reels')
      .then((res) => {
        console.log('Reels response:', res.data);
        setReels(res.data || []);
      })
      .catch((err) => {
        console.error('Failed to fetch reels:', err);
        setError('Failed to load reels');
        setReels([]);
      })
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <main className="page" style={{ padding: '100px 24px 32px' }}>
        <div style={{ minHeight: '60vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
          <div className="spinner" />
          <p style={{ marginTop: '16px', color: 'var(--text-dim)' }}>Loading reels...</p>
        </div>
      </main>
    );
  }

  if (error) {
    return (
      <main className="page" style={{ padding: '100px 24px 32px' }}>
        <h1 className="section-title" style={{ marginBottom: '32px' }}>Movie Reels</h1>
        <div style={{ minHeight: '60vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center' }}>
          <div style={{ fontSize: '3rem', marginBottom: '16px' }}>⚠️</div>
          <h2 style={{ fontSize: '1.5rem', marginBottom: '8px' }}>Unable to Load Reels</h2>
          <p style={{ color: 'var(--text-dim)', maxWidth: '400px' }}>{error}</p>
        </div>
      </main>
    );
  }

  return (
    <main className="page" style={{ padding: '100px 24px 32px' }}>
      <h1 className="section-title" style={{ marginBottom: '32px' }}>Movie Reels</h1>
      {reels.length > 0 ? (
        <section style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '16px' }}>
          {reels.map((item) => (
            <article
              key={item.id}
              className="glass"
              style={{
                overflow: 'hidden',
                transition: 'transform 0.3s, box-shadow 0.3s',
                cursor: 'pointer'
              }}
              onMouseEnter={e => {
                e.currentTarget.style.transform = 'translateY(-4px)';
                e.currentTarget.style.boxShadow = 'var(--shadow-red)';
              }}
              onMouseLeave={e => {
                e.currentTarget.style.transform = 'none';
                e.currentTarget.style.boxShadow = 'none';
              }}
            >
              {item.poster && (
                <img
                  src={item.poster}
                  alt={item.title}
                  style={{ width: '100%', height: '280px', objectFit: 'cover', display: 'block' }}
                />
              )}
              <div style={{ padding: '16px' }}>
                <h3 style={{ margin: '0 0 8px 0', fontFamily: 'var(--font-display)', fontSize: '1rem', fontWeight: 600, letterSpacing: '0.5px' }}>
                  {item.title}
                </h3>
                <p style={{ margin: 0, color: 'var(--text-dim)', fontSize: '0.85rem' }}>
                  {item.year} • {item.genre}
                </p>
                {item.rating && (
                  <p style={{ margin: '8px 0 0 0', color: 'var(--red)', fontSize: '0.85rem', fontWeight: '600' }}>
                    ⭐ {item.rating}
                  </p>
                )}
              </div>
            </article>
          ))}
        </section>
      ) : (
        <div style={{
          gridColumn: '1 / -1',
          minHeight: '60vh',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          textAlign: 'center'
        }}>
          <div style={{ fontSize: '3rem', marginBottom: '16px', opacity: 0.5 }}>🎬</div>
          <h2 style={{ fontSize: '1.3rem', marginBottom: '8px' }}>No Reels Available</h2>
          <p style={{ color: 'var(--text-dim)', maxWidth: '400px' }}>
            Check back soon for new movie reels and highlights.
          </p>
        </div>
      )}
    </main>
  );
}
